pub const SelectionNotifyEvent = struct {
    subtype: SelectionEvent,
    window: xproto.Window,
    owner: xproto.Window,
    selection: xproto.Atom,
    timestamp: u32,
    selection_timestamp: u32,

    pub fn toBytes(self: @This()) EncodeError![32]u8 {
        var packet: [32]u8 = std.mem.zeroes([32]u8);
        var writer_impl: std.Io.Writer = .fixed(&packet);
        const writer = &writer_impl;
        try writer.writeByte(0);
        try writer.writeByte(@intCast(@intFromEnum(self.subtype)));
        try writer.writeInt(u16, 0, .native);
        try writer.writeInt(u32, @intFromEnum(self.window), .native);
        try writer.writeInt(u32, @intFromEnum(self.owner), .native);
        try writer.writeInt(u32, @intFromEnum(self.selection), .native);
        try writer.writeInt(u32, self.timestamp, .native);
        try writer.writeInt(u32, self.selection_timestamp, .native);
        try writer.splatByteAll(0, 8);
        return packet;
    }

    pub fn decode(reader: *std.Io.Reader) DecodeError!@This() {
        _ = try reader.takeByte();
        const subtype = @as(SelectionEvent, @enumFromInt(try reader.takeInt(u8, .native)));
        _ = try reader.takeInt(u16, .native);
        const window = @as(xproto.Window, @enumFromInt(try reader.takeInt(u32, .native)));
        const owner = @as(xproto.Window, @enumFromInt(try reader.takeInt(u32, .native)));
        const selection = @as(xproto.Atom, @enumFromInt(try reader.takeInt(u32, .native)));
        const timestamp = try reader.takeInt(u32, .native);
        const selection_timestamp = try reader.takeInt(u32, .native);
        _ = try reader.take(8);
        return .{
            .subtype = subtype,
            .window = window,
            .owner = owner,
            .selection = selection,
            .timestamp = timestamp,
            .selection_timestamp = selection_timestamp,
        };
    }
};

